import os
import agentops
from openai import OpenAI

agentops.init(api_key=os.environ["AGENTOPS_API_KEY"])
client = OpenAI()

# Decorate agent classes to appear as named entities in the dashboard.
@agentops.track_agent(name="ResearchAgent")
class ResearchAgent:
    def __init__(self):
        self.messages = [
            {
                "role": "system",
                "content": (
                    "You are a research agent. "
                    "Call search_web when you need information. "
                    "Synthesize findings into a concise report."
                ),
            }
        ]

    def search_web(self, query: str) -> str:
        # In production this would call a real search API.
        return f"[Search results for '{query}']: Relevant documents found."

    def run(self, topic: str) -> str:
        self.messages.append({"role": "user", "content": f"Research: {topic}"})

        tools = [
            {
                "type": "function",
                "function": {
                    "name": "search_web",
                    "description": "Search the web for information on a topic.",
                    "parameters": {
                        "type": "object",
                        "properties": {"query": {"type": "string"}},
                        "required": ["query"],
                    },
                },
            }
        ]

        # Step 1: plan and select tools
        response = client.chat.completions.create(
            model="gpt-4o", messages=self.messages, tools=tools
        )
        msg = response.choices[0].message
        self.messages.append(msg)

        # Step 2: execute tool calls (AgentOps captures these as action events)
        if msg.tool_calls:
            for tc in msg.tool_calls:
                result = self.search_web(tc.function.arguments)
                self.messages.append(
                    {"role": "tool", "tool_call_id": tc.id, "content": result}
                )

        # Step 3: synthesize with the retrieved context
        final = client.chat.completions.create(
            model="gpt-4o", messages=self.messages
        )
        return final.choices[0].message.content


agent = ResearchAgent()
try:
    report = agent.run("quantum computing advances in 2024")
    print(report)
    agentops.end_session("Success")
except Exception as exc:
    agentops.end_session("Fail", end_state_reason=str(exc))
    raise

import os
import agentops
from anthropic import Anthropic

# Tags applied to every session in this process.
agentops.init(
    api_key=os.environ["AGENTOPS_API_KEY"],
    tags=["batch", "summarization", "production"],
)

client = Anthropic()

def summarize_document(doc_id: str, text: str) -> dict:
    # Start an explicit session per document for isolated tracking.
    session = agentops.start_session(tags=[f"doc:{doc_id}"])
    try:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[
                {
                    "role": "user",
                    "content": f"Summarize the following in 3 bullet points:\n\n{text}",
                }
            ],
        )
        summary = response.content[0].text
        session.end_session("Success")
        return {"doc_id": doc_id, "summary": summary, "status": "ok"}
    except Exception as exc:
        session.end_session("Fail", end_state_reason=str(exc))
        return {"doc_id": doc_id, "summary": None, "status": "error"}


documents = [
    ("doc-001", "Long document text about renewable energy..."),
    ("doc-002", "Long document text about machine learning..."),
]

for doc_id, text in documents:
    result = summarize_document(doc_id, text)
    print(result)

import os
import json
import agentops
from openai import OpenAI

agentops.init(
    api_key=os.environ["AGENTOPS_API_KEY"],
    tags=["support-agent", "production"],
)

client = OpenAI()

@agentops.track_agent(name="SupportAgent")
class SupportAgent:
    def handle_ticket(self, ticket_id: str, category: str, body: str) -> dict:
        session = agentops.start_session(
            tags=[f"ticket:{ticket_id}", f"category:{category}"]
        )
        try:
            result = self._process(body)
            outcome = "Success" if result["action"] == "respond" else "Escalated"
            session.end_session(outcome)
            return result
        except Exception as exc:
            session.end_session("Fail", end_state_reason=str(exc))
            raise

    def _process(self, body: str) -> dict:
        tools = [
            {
                "type": "function",
                "function": {
                    "name": "query_knowledge_base",
                    "description": "Search internal knowledge base for relevant articles.",
                    "parameters": {
                        "type": "object",
                        "properties": {"query": {"type": "string"}},
                        "required": ["query"],
                    },
                },
            },
            {
                "type": "function",
                "function": {
                    "name": "escalate_to_human",
                    "description": "Escalate the ticket to a human agent.",
                    "parameters": {
                        "type": "object",
                        "properties": {"reason": {"type": "string"}},
                        "required": ["reason"],
                    },
                },
            },
        ]

        messages = [
            {
                "role": "system",
                "content": (
                    "You are a customer support agent. "
                    "Resolve tickets using the knowledge base when possible. "
                    "Escalate only when the knowledge base does not cover the issue."
                ),
            },
            {"role": "user", "content": body},
        ]

        for _ in range(3):  # max 3 tool rounds before forced escalation
            response = client.chat.completions.create(
                model="gpt-4o", messages=messages, tools=tools
            )
            msg = response.choices[0].message
            messages.append(msg)

            if not msg.tool_calls:
                # Model produced a final answer without more tool calls
                return {"action": "respond", "reply": msg.content}

            for tc in msg.tool_calls:
                fn = tc.function.name
                args = json.loads(tc.function.arguments)
                if fn == "escalate_to_human":
                    return {"action": "escalate", "reason": args["reason"]}
                # Simulate knowledge-base lookup
                tool_result = f"KB result for '{args['query']}': General guidance available."
                messages.append(
                    {"role": "tool", "tool_call_id": tc.id, "content": tool_result}
                )

        return {"action": "escalate", "reason": "max tool rounds exceeded"}


agent = SupportAgent()
result = agent.handle_ticket("TKT-4821", "billing", "I was charged twice this month.")
print(result)
